const SUBJECT_MAP = {calculus:'Calculus','linear-algebra':'Linear Algebra',physics:'Physics','differential-equations':'Differential Equations','sequences-series':'Sequences & Series'};
const SUBJECT_COLORS = {calculus:'#ef4444','linear-algebra':'#3b82f6',physics:'#10b981','differential-equations':'#f59e0b','sequences-series':'#a855f7'};let state = { user: null, uid: null, currentPage: 'dashboard', currentTopic: null, searchQuery: '', subjectFilter: 'all', notes: [], progress: {}, theme: localStorage.getItem('al_theme') || (window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'), animParams: {}, animPlaying: true, animSpeed: 1, isLoading: true };

function applyTheme(t) { state.theme = t; document.documentElement.classList.toggle('dark', t === 'dark'); localStorage.setItem('al_theme', t); const icon = document.getElementById('themeIcon'); if (icon) icon.className = t === 'dark' ? 'fas fa-sun text-lg' : 'fas fa-moon text-lg'; }
function toggleTheme() { applyTheme(state.theme === 'dark' ? 'light' : 'dark'); }
function showToast(msg, type='info') { const c = document.getElementById('toastContainer'); const icons = {info:'fa-info-circle',success:'fa-check-circle',error:'fa-exclamation-circle',warning:'fa-exclamation-triangle'}; const colors = {info:'var(--accent)',success:'#10b981',error:'#ef4444',warning:'#f59e0b'}; const el = document.createElement('div'); el.className = 'toast'; el.innerHTML = `<i class="fas ${icons[type]}" style="color:${colors[type]}"></i><span>${msg}</span>`; c.appendChild(el); setTimeout(() => { el.style.animation = 'slideOut .3s ease forwards'; setTimeout(() => el.remove(), 300); }, 3000); }
function generateId() { return 'n' + Date.now().toString(36) + Math.random().toString(36).substr(2, 5); }
function escapeHtml(str) { const d = document.createElement('div'); d.textContent = str; return d.innerHTML; }
function escapeAttr(str) { return (str || '').replace(/"/g, '&quot;').replace(/'/g, '&#39;'); }

function showAuth(mode) { document.getElementById('authModal').classList.add('show'); toggleAuth(mode); }
function closeAuth() { document.getElementById('authModal').classList.remove('show'); }
function toggleAuth(mode) { document.getElementById('authLogin').style.display = mode === 'login' ? 'block' : 'none'; document.getElementById('authRegister').style.display = mode === 'register' ? 'block' : 'none'; }

async function handleLogin() { const email = document.getElementById('loginEmail').value.trim(); const pass = document.getElementById('loginPass').value; const btn = document.getElementById('loginBtn'); if (!email || !pass) return showToast('Please fill in all fields','warning'); btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Signing In...'; try { await auth.signInWithEmailAndPassword(email, pass); closeAuth(); showToast('Welcome back!', 'success'); } catch (error) { showToast(error.message.replace('Firebase: ', ''), 'error'); } finally { btn.disabled = false; btn.innerHTML = 'Sign In'; } }
async function handleRegister() { const name = document.getElementById('regName').value.trim(); const email = document.getElementById('regEmail').value.trim(); const pass = document.getElementById('regPass').value; const diff = document.getElementById('regDiff').value; const btn = document.getElementById('regBtn'); if (!name || !email || !pass) return showToast('Please fill in all fields','warning'); if (pass.length < 6) return showToast('Password must be at least 6 characters','warning'); btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Creating Account...'; try { const cred = await auth.createUserWithEmailAndPassword(email, pass); await cred.user.updateProfile({ displayName: name }); await db.collection('users').doc(cred.user.uid).set({ name, email, difficulty: diff, createdAt: firebase.firestore.FieldValue.serverTimestamp() }); closeAuth(); showToast('Account created! Welcome to AnimaLearn', 'success'); } catch (error) { showToast(error.message.replace('Firebase: ', ''), 'error'); } finally { btn.disabled = false; btn.innerHTML = 'Create Account'; } }
async function handleOAuth(providerName) { let provider; if (providerName === 'Google') provider = new firebase.auth.GoogleAuthProvider(); if (providerName === 'GitHub') provider = new firebase.auth.GithubAuthProvider(); try { const result = await auth.signInWithPopup(provider); const userDoc = await db.collection('users').doc(result.user.uid).get(); if (!userDoc.exists) { await db.collection('users').doc(result.user.uid).set({ name: result.user.displayName || providerName + ' User', email: result.user.email, difficulty: 'intermediate', createdAt: firebase.firestore.FieldValue.serverTimestamp() }); } closeAuth(); showToast('Signed in with ' + providerName, 'success'); } catch (error) { if (error.code !== 'auth/popup-closed-by-user') showToast(error.message, 'error'); } }
async function handleLogout() { if (!state.user) { showAuth('login'); return; } try { await auth.signOut(); showToast('Signed out successfully', 'info'); } catch(e) { showToast('Logout failed', 'error'); } }

auth.onAuthStateChanged(async (user) => { if (user) { state.user = { name: user.displayName || user.email.split('@')[0], email: user.email, avatar: (user.displayName || user.email)[0].toUpperCase(), difficulty: 'intermediate' }; state.uid = user.uid; try { const doc = await db.collection('users').doc(user.uid).get(); if(doc.exists) state.user.difficulty = doc.data().difficulty || 'intermediate'; } catch(e) {} await loadUserDataFromFirestore(); } else { state.user = null; state.uid = null; state.notes = []; state.progress = {}; } updateUserUI(); state.isLoading = false; navigate(state.currentPage); });

async function loadUserDataFromFirestore() { if (!state.uid) return; try { const notesSnapshot = await db.collection('users').doc(state.uid).collection('notes').orderBy('updatedAt', 'desc').get(); state.notes = notesSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() })); const progressSnapshot = await db.collection('users').doc(state.uid).collection('progress').get(); state.progress = {}; progressSnapshot.docs.forEach(doc => { state.progress[doc.id] = doc.data(); }); } catch (error) { console.error("Error loading data: ", error); showToast("Failed to load saved data", "error"); } }
async function saveNoteToDb(noteId, data) { if (!state.uid) return; try { await db.collection('users').doc(state.uid).collection('notes').doc(noteId).set(data, { merge: true }); } catch (e) { showToast("Failed to save note.", "error"); } }
async function deleteNoteFromDb(noteId) { if (!state.uid) return; try { await db.collection('users').doc(state.uid).collection('notes').doc(noteId).delete(); } catch (e) { showToast("Failed to delete note.", "error"); } }
async function updateProgressInDb(topicId, data) { if (!state.uid) return; try { await db.collection('users').doc(state.uid).collection('progress').doc(topicId).set(data, { merge: true }); } catch (e) { console.error("Progress update failed", e); } }

function updateUserUI() { const u = state.user; document.getElementById('sidebarAvatar').textContent = u ? u.avatar : '?'; document.getElementById('sidebarName').textContent = u ? u.name : 'Guest'; document.getElementById('sidebarEmail').textContent = u ? u.email : 'Sign in to get started'; document.getElementById('headerAuthBtn').style.display = u ? 'none' : 'flex'; document.getElementById('logoutIcon').style.display = u ? '' : 'none'; }
function toggleSidebar() { const sb = document.getElementById('sidebar'); const ov = document.getElementById('mobileOverlay'); sb.classList.toggle('open'); ov.classList.toggle('show'); }

function navigate(page, param) { stopAnimation(); state.currentPage = page; if (param) state.subjectFilter = param; document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active')); const activeNav = document.querySelector(`.nav-item[data-page="${page}"]`); if (activeNav) activeNav.classList.add('active'); const main = document.getElementById('mainContent'); main.scrollTop = 0; if (state.isLoading) { main.innerHTML = '<div class="loader"></div>'; return; } switch(page) { case 'dashboard': main.innerHTML = renderDashboard(); initDashboard(); break; case 'topics': main.innerHTML = renderTopics(); initTopics(); break; case 'topic-detail': state.currentTopic = param; main.innerHTML = renderTopicDetail(param); initTopicDetail(param); break; case 'notes': main.innerHTML = renderNotes(); initNotes(); break; case 'note-editor': main.innerHTML = renderNoteEditor(param); initNoteEditor(param); break; case 'references': main.innerHTML = renderReferences(); initReferences(); break; case 'search': main.innerHTML = renderSearchResults(param); break; default: main.innerHTML = renderDashboard(); initDashboard(); } document.getElementById('sidebar').classList.remove('open'); document.getElementById('mobileOverlay').classList.remove('show'); }
function performSearch(q) { if (!q.trim()) return; state.searchQuery = q.trim(); navigate('search', q.trim()); }

function renderDashboard() { const totalTopics = TOPICS.length; const completed = Object.keys(state.progress).filter(k => state.progress[k].percent >= 100).length; const totalNotes = state.notes.length; const animsViewed = Object.keys(state.progress).length; const recentTopics = TOPICS.slice(0, 4); const recentNotes = state.notes.slice(0, 3); return `<div class="max-w-6xl mx-auto"><div class="mb-8 fade-up"><h2 class="font-display text-3xl md:text-4xl font-bold mb-2">${state.user ? 'Welcome back, ' + state.user.name : 'Welcome to AnimaLearn'}</h2><p style="color:var(--text2)" class="text-lg">Transform abstract theory into visual understanding</p></div><div class="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8"><div class="card stat-card fade-up fade-up-1"><div class="stat-num">${totalTopics}</div><div class="stat-label">Topics Available</div></div><div class="card stat-card fade-up fade-up-2"><div class="stat-num">${completed}</div><div class="stat-label">Completed</div></div><div class="card stat-card fade-up fade-up-3"><div class="stat-num">${totalNotes}</div><div class="stat-label">Notes Created</div></div><div class="card stat-card fade-up fade-up-4"><div class="stat-num">${animsViewed}</div><div class="stat-label">Animations Viewed</div></div></div><div class="grid md:grid-cols-3 gap-6 mb-8"><div class="md:col-span-2 fade-up fade-up-2"><h3 class="font-display text-xl font-bold mb-4">Continue Learning</h3><div class="grid sm:grid-cols-2 gap-4">${recentTopics.map(t => { const p = state.progress[t.id] || {percent:0}; const sc = SUBJECT_COLORS[t.subject] || '#888'; return `<div class="card cursor-pointer" onclick="navigate('topic-detail','${t.id}')"><div class="flex items-center gap-2 mb-2"><span class="badge badge-${t.subject}">${t.subjectLabel}</span><span class="badge badge-${t.difficulty}">${t.difficulty}</span></div><h4 class="font-display font-semibold mb-2">${t.title}</h4><p class="text-xs mb-3 line-clamp-2" style="color:var(--text2)">${t.description}</p><div class="progress-bar"><div class="progress-fill" style="width:${p.percent}%;background:${sc}"></div></div><p class="text-xs mt-1" style="color:var(--text2)">${p.percent}% complete</p></div>`; }).join('')}</div></div><div class="fade-up fade-up-3"><h3 class="font-display text-xl font-bold mb-4">Quick Actions</h3><div class="space-y-3"><button class="btn btn-primary w-full justify-center" onclick="navigate('topics')"><i class="fas fa-shapes"></i> Browse All Topics</button><button class="btn btn-outline w-full justify-center" onclick="navigate('note-editor','new')"><i class="fas fa-plus"></i> Create New Note</button><button class="btn btn-outline w-full justify-center" onclick="navigate('references')"><i class="fas fa-book-open"></i> Reference Library</button></div><h3 class="font-display text-xl font-bold mb-4 mt-8">Recent Notes</h3><div class="space-y-2">${recentNotes.length === 0 ? '<p class="text-sm" style="color:var(--text2)">No notes yet. Start writing!</p>' : recentNotes.map(n => `<div class="card cursor-pointer py-3 px-4" onclick="navigate('note-editor','${n.id}')"><p class="font-semibold text-sm">${n.title}</p><p class="text-xs" style="color:var(--text2)">${n.updatedAt ? new Date(n.updatedAt).toLocaleDateString() : new Date(n.createdAt).toLocaleDateString()}</p></div>`).join('')}</div></div></div><div class="fade-up fade-up-4"><h3 class="font-display text-xl font-bold mb-4">Subjects Overview</h3><div class="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-5 gap-4">${Object.entries(SUBJECT_MAP).map(([k,v]) => { const c = SUBJECT_COLORS[k]; const count = TOPICS.filter(t => t.subject === k).length; return `<div class="card cursor-pointer text-center" onclick="navigate('topics','${k}')"><div class="w-10 h-10 rounded-full mx-auto mb-2 flex items-center justify-center" style="background:${c}20;color:${c}"><i class="fas fa-${k==='calculus'?'infinity':k==='linear-algebra'?'border-all':k==='physics'?'bolt':k==='differential-equations'?'wave-square':'chart-line'}"></i></div><p class="font-semibold text-sm">${v}</p><p class="text-xs" style="color:var(--text2)">${count} topics</p></div>`; }).join('')}</div></div></div>`; }
