function renderTopics() { const filtered = state.subjectFilter === 'all' ? TOPICS : TOPICS.filter(t => t.subject === state.subjectFilter); return `<div class="max-w-6xl mx-auto"><div class="mb-6 fade-up"><h2 class="font-display text-3xl font-bold mb-2">Topics Library</h2><p style="color:var(--text2)">Explore ${TOPICS.length} interactive topics across 5 subjects</p></div><div class="flex flex-wrap gap-2 mb-6 fade-up fade-up-1"><button class="subject-chip ${state.subjectFilter==='all'?'active':''}" onclick="state.subjectFilter='all';navigate('topics')">All Topics</button>${Object.entries(SUBJECT_MAP).map(([k,v]) => `<button class="subject-chip ${state.subjectFilter===k?'active':''}" onclick="state.subjectFilter='${k}';navigate('topics')">${v}</button>`).join('')}</div><div class="grid sm:grid-cols-2 lg:grid-cols-3 gap-5">${filtered.map((t,i) => { const p = state.progress[t.id] || {percent:0}; const sc = SUBJECT_COLORS[t.subject]; return `<div class="card cursor-pointer fade-up fade-up-${Math.min(i%4+1,4)}" onclick="navigate('topic-detail','${t.id}')"><div class="flex items-center justify-between mb-3"><span class="badge badge-${t.subject}">${t.subjectLabel}</span><span class="badge badge-${t.difficulty}">${t.difficulty}</span></div><h3 class="font-display text-lg font-bold mb-2">${t.title}</h3><p class="text-sm mb-4 line-clamp-2" style="color:var(--text2)">${t.description}</p><div class="progress-bar mb-1"><div class="progress-fill" style="width:${p.percent}%;background:${sc}"></div></div><div class="flex justify-between text-xs" style="color:var(--text2)"><span>${p.percent}% complete</span><span><i class="fas fa-play-circle mr-1"></i>View Animation</span></div></div>`; }).join('')}</div></div>`; }
